namespace sv_f711db8d05634b2e83390445a3a7cd0f;

public enum Theme { Light, Dark, System }

public record ThemeInfo(Theme Theme = Theme.Light, string AccentColor = "#0d6efd");

@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<span class="theme-indicator" style="color: @(Theme?.AccentColor ?? "#0d6efd");">
    @GetIcon() @Theme?.Theme
</span>

<button class="btn btn-sm btn-outline-secondary ms-2" @onclick="CycleTheme">
    Toggle Theme
</button>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private async Task CycleTheme()
    {
        var current = Theme ?? new ThemeInfo();
        var next = current.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
        await ThemeSource.NotifyChangedAsync(current with { Theme = next });
    }

    private string GetIcon() => Theme?.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select" style="max-width:200px"
            value="@selectedTheme" @onchange="OnThemeChanged">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <option value="@t">@t</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@accentColor" @onchange="OnAccentChanged" />
</div>

<div class="mt-4 p-3 border rounded" style="border-color: @accentColor !important;">
    <strong>Preview:</strong>
    Current theme is <strong>@selectedTheme</strong> with accent
    <span style="color: @accentColor;">@accentColor</span>.
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private Theme selectedTheme;
    private string accentColor = "#0d6efd";

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            selectedTheme = Theme.Theme;
            accentColor = Theme.AccentColor;
        }
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        selectedTheme = Enum.Parse<Theme>((string)e.Value!);
        await NotifyChange();
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        accentColor = (string)e.Value!;
        await NotifyChange();
    }

    private Task NotifyChange() =>
        ThemeSource.NotifyChangedAsync(new ThemeInfo(selectedTheme, accentColor));
}

