@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<span class="theme-indicator" style="color: @(Theme?.AccentColor ?? "#0d6efd");">
    @GetIcon() @Theme?.Mode
</span>

<button class="btn btn-sm btn-outline-secondary ms-2" @onclick="CycleTheme">
    Toggle Theme
</button>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private async Task CycleTheme()
    {
        var current = Theme ?? new ThemeInfo();
        var next = current.Mode switch
        {
            ThemeMode.Light => ThemeMode.Dark,
            ThemeMode.Dark => ThemeMode.System,
            _ => ThemeMode.Light
        };
        await ThemeSource.NotifyChangedAsync(current with { Mode = next });
    }

    private string GetIcon() => Theme?.Mode switch
    {
        ThemeMode.Dark => "🌙",
        ThemeMode.System => "💻",
        _ => "☀️"
    };
}

